  function imageFileToBase64(file: File) {
    return new Promise<string>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result));
      reader.onerror = () => reject(reader.error);
      reader.readAsDataURL(file);
    });
  }

  async function openListing(listing: Listing) {
    setSelectedListing(listing);
    setCrashRecoveredRecentIds((currentIds) => [
      listing.id,
      ...currentIds.filter((listingId) => listingId !== listing.id),
    ].slice(0, 8));
    setInquiryForm({ name: "", email: "", phone: "", message: "" });
    setInspectionForm({
      name: "",
      email: "",
      phone: "",
      preferredDate: "",
      preferredTime: "",
      message: "",
    });
    setModal("details");

    const newView: Omit<PropertyView, "id"> = {
      listingId: listing.id,
      listingTitle: listing.title,
      viewedAt: new Date().toISOString(),
    };

    if (supabase) {
      const { error } = await supabase.from("property_views").insert({
        listing_id: listing.id,
        listing_title: listing.title,
      });

      if (error) {
        console.error(error);
        return;
      }

      if (adminUnlocked) {
        await loadDatabasePropertyViews();
      await loadDatabasePropertyImages();
      }
    } else {
      setPropertyViews((current) => [{ ...newView, id: Date.now() }, ...current]);
    }
  }

  function toggleCrashRecoveredSavedListing(listing: Listing) {
    setCrashRecoveredSavedIds((currentIds) => {
      if (currentIds.includes(listing.id)) {
        showSuccess("Recovered saved property removed.");
        return currentIds.filter((listingId) => listingId !== listing.id);
      }

      showSuccess("Recovered saved property added.");
      return [listing.id, ...currentIds].slice(0, 50);
    });
  }

  function updateCrashRecoveredNote(listingId: number, note: string) {
    setCrashRecoveredNotes((currentNotes) => ({
      ...currentNotes,
      [listingId]: note,
    }));
  }

  function toggleCrashRecoveredCompare(listing: Listing) {
    setCrashRecoveredCompareIds((currentIds) => {
      if (currentIds.includes(listing.id)) {
        showSuccess("Recovered compare item removed.");
        return currentIds.filter((listingId) => listingId !== listing.id);
      }

      showSuccess("Recovered compare item added.");
      return [listing.id, ...currentIds].slice(0, 4);
    });
  }

  function clearCrashRecoveredActivity() {
    setCrashRecoveredSavedIds([]);
    setCrashRecoveredNotes({});
    setCrashRecoveredCompareIds([]);
    setCrashRecoveredRecentIds([]);
    showSuccess("Recovered saved notes, compare list, and recent activity cleared.");
  }

  async function approveAllCrashRecoveredPendingListings() {
    if (!canApproveListings) {
      showSuccess("Your role cannot approve property listings.");
      return;
    }

    if (pendingListings.length === 0) {
      showSuccess("No pending listing to approve.");
      return;
    }

    for (const listing of pendingListings) {
      await approveListing(listing.id);
    }

    showSuccess("Recovered bulk action completed: pending listings approved.");
  }

  async function verifyAllCrashRecoveredOwners() {
    if (!canEditListings) {
      showSuccess("Your role cannot verify owners.");
      return;
    }

    const unverifiedListings = listings.filter(
      (listing) => !listing.ownerVerified || !listing.contactProfileVerified
    );

    if (unverifiedListings.length === 0) {
      showSuccess("All owners/contacts are already marked verified.");
      return;
    }

    if (supabase) {
      const { error } = await supabase
        .from("listings")
        .update({ owner_verified: true, contact_profile_verified: true })
        .in(
          "id",
          unverifiedListings.map((listing) => listing.id)
        );

      if (error) {
        console.error(error);
        showSuccess("Unable to verify owners from recovered bulk center.");
        return;
      }

      await loadDatabaseListings();
    } else {
      setListings((currentListings) =>
        currentListings.map((listing) => ({
          ...listing,
          ownerVerified: true,
          contactProfileVerified: true,
        }))
      );
    }

    await createAdminActivityLog(
      "Recovered bulk owner verification",
      "Listing",
      "bulk",
      `${unverifiedListings.length} owner/contact profiles were marked verified from the recovered crash feature center.`
    );

    showSuccess("Recovered bulk action completed: owners verified.");
  }

  async function featureTopCrashRecoveredListing() {
    if (!canEditListings) {
      showSuccess("Your role cannot feature listings.");
      return;
    }

    const topListing = topViewedListings[0] || crashRecoveredHighestValueListing;

    if (!topListing) {
      showSuccess("No listing available to feature.");
      return;
    }

    if (supabase) {
      const { error } = await supabase
        .from("listings")
        .update({ featured: true, featured_rank: 1 })
        .eq("id", topListing.id);

      if (error) {
        console.error(error);
        showSuccess("Unable to feature top recovered listing.");
        return;
      }

      await loadDatabaseListings();
    } else {
      setListings((currentListings) =>
        currentListings.map((listing) =>
          listing.id === topListing.id
            ? { ...listing, featured: true, featuredRank: 1 }
            : listing
        )
      );
    }

    await createAdminActivityLog(
      "Recovered featured listing",
      "Listing",
      String(topListing.id),
      `${topListing.title} was featured from the recovered crash feature center.`
    );

    showSuccess("Recovered top listing featured.");
  }

  async function copyCrashRecoveredReport() {
    const report = [
      "INAMAAD RECOVERED CRASH-FILE FEATURES REPORT",
      `Generated: ${new Date().toLocaleString()}`,
      "",
      `Market score: ${crashRecoveredMarketScore}%`,
      `Listings: ${listings.length}`,
      `Verified listings: ${verifiedListings.length}`,
      `Pending listings: ${pendingListings.length}`,
      `Total property value: ${formatNairaCompact(totalPropertyValue)}`,
      `Verified property value: ${formatNairaCompact(verifiedPropertyValue)}`,
      `Average listing value: ${formatNairaCompact(crashRecoveredAverageListingValue)}`,
      `Highest value listing: ${crashRecoveredHighestValueListing?.title || "None"}`,
      `Saved recovered notes: ${Object.keys(crashRecoveredNotes).length}`,
      `Compare items: ${crashRecoveredCompareListings.length}`,
      `Recent recovered views: ${crashRecoveredRecentListings.length}`,
      `Top state: ${crashRecoveredStateExplorerCounts[0]?.stateName || "None"}`,
      `Top viewed listing: ${mostViewedProperty}`,
    ].join("\n");

    try {
      await navigator.clipboard.writeText(report);
      showSuccess("Recovered crash-file report copied.");
    } catch {
      showSuccess(report);
    }
  }

  async function exportCrashRecoveredCsv() {
    if (!canExportReports) {
      showSuccess("Your role cannot export reports.");
      return;
    }

    downloadCsv(
      "inamaad-recovered-crash-features.csv",
      ["Metric", "Value"],
      [
        ["Market score", `${crashRecoveredMarketScore}%`],
        ["Listings", listings.length],
        ["Verified listings", verifiedListings.length],
        ["Pending listings", pendingListings.length],
        ["Total property value", totalPropertyValue],
        ["Verified property value", verifiedPropertyValue],
        ["Average listing value", crashRecoveredAverageListingValue],
        ["Highest value listing", crashRecoveredHighestValueListing?.title || ""],
        ["Saved recovered notes", Object.keys(crashRecoveredNotes).length],
        ["Compare items", crashRecoveredCompareListings.length],
        ["Recent recovered views", crashRecoveredRecentListings.length],
        ["Top state", crashRecoveredStateExplorerCounts[0]?.stateName || ""],
        ["Top viewed property", mostViewedProperty],
        ["Generated at", new Date().toISOString()],
      ]
    );

    await createAdminActivityLog(
      "Recovered crash report exported",
      "Report",
      "crash-recovered",
      "Staff exported the safely rebuilt crashed-file feature report."
    );

    showSuccess("Recovered crash-file CSV exported.");
  }

  async function copyListingShareLink(listing: Listing) {
    const shareUrl = buildListingShareUrl(listing.id);

    try {
      await navigator.clipboard.writeText(shareUrl);
      showSuccess("Property link copied. You can now share it with clients.");
    } catch {
      showSuccess(shareUrl);
    }
  }

  async function shareListing(listing: Listing) {
    const shareUrl = buildListingShareUrl(listing.id);
    const shareText = buildListingShareText(listing);

    if (navigator.share) {
      try {
        await navigator.share({
          title: listing.title,
          text: shareText,
          url: shareUrl,
        });
        return;
      } catch {
        // User cancelled native sharing, so fall back to copying.
      }
    }

    await copyListingShareLink(listing);
  }

  function shareListingToWhatsApp(listing: Listing) {
    window.open(
      `https://wa.me/?text=${encodeURIComponent(buildListingShareText(listing))}`,
      "_blank",
      "noopener,noreferrer"
    );
  }

